INSERT INTO `textos` (`id`, `titulo`, `linhafina`, `texto`, `img`, `url`, `tipo`, `visualizacao`, `nr`) VALUES
(27, 'TREINAMENTO NR 05 CIPA - COMISSÃO INTERNA DE PREVENÇÃO DE ACIDENTES', 'Público Alvo: Membros da CIPA, Diretores, Gerentes, Engenheiros, Técnicos, Operadores e Membros da CIPA eleitos ou indicados pelo Empregador.  Descrição: NR 05 – A COMISSÃO INTERNA DE PREVENÇÃO DE ACIDENTES - CIPA - tem como objetivo a prevenção de aciden', 'Público Alvo: Membros da CIPA, Diretores, Gerentes, Engenheiros, Técnicos, Operadores e Membros da CIPA eleitos ou indicados pelo Empregador.\r\n\r\nDescrição: NR 05 - A COMISSÃO INTERNA DE PREVENÇÃO DE ACIDENTES - CIPA - tem como objetivo a prevenção de acidentes e doenças decorrentes do trabalho, de modo a tornar compatível permanentemente o trabalho com a preservação da vida e a promoção da saúde do trabalhador.\r\n\r\nCarga Horária: 20 Horas\r\n\r\nConteúdo programático:\r\n\r\n1. Estudo do ambiente, das condições de trabalho, bem como dos riscos originados do processo produtivo;\r\n\r\n2. Metodologia de investigação e análise de acidentes e doenças do trabalho;\r\n\r\n3. Noções sobre acidentes e doenças do trabalho decorrentes de exposição aos riscos existentes na empresa;\r\n\r\n4. Noções sobre a Síndrome da Imunodeficiência Adquirida – AIDS e medidas de prevenção;\r\n\r\n5. Noções sobre as legislações trabalhista e previdenciária relativas à segurança e saúde no trabalho;\r\n\r\n6. Princípios gerais de higiene do trabalho e de medidas de controle dos riscos;\r\n\r\n7. Organização da CIPA e outros assuntos necessários ao exercício das atribuições da Comissão.', '07.webp', 'treinamento-nr-05-cipa-comissao-interna-de-prevencao-de-acidentes', 'treinamento', 1928, 'NR05'),
(28, 'TREINAMENTO NR 06 - EQUIPAMENTO DE PROTEÇÃO INDIVIDUAL - EPI', 'NR 6 - EQUIPAMENTO DE PROTEÇÃO INDIVIDUAL - EPI - Para os fins de aplicação desta Norma Regulamentadora – NR, considera-se Equipamento de Proteção Individual - EPI, todo dispositivo ou produto, de uso individual utilizado pelo trabalhador, destinado à pro', 'Público Alvo: Todos os empregados que utilizam EPI.\r\n\r\nDescrição: NR 6 - EQUIPAMENTO DE PROTEÇÃO INDIVIDUAL - EPI – Para os fins de aplicação desta Norma Regulamentadora – NR, considera-se Equipamento de Proteção Individual - EPI, todo dispositivo ou produto, de uso individual utilizado pelo trabalhador, destinado à proteção de riscos suscetíveis de ameaçar a segurança e a saúde no trabalho.\r\n\r\nCarga horária: a partir de 04 Horas\r\n\r\nConteúdo programático:\r\n\r\n1. Introdução a Engenharia de Segurança do Trabalho;\r\n\r\n2. Responsabilidades do Empregador e do Empregado;\r\n\r\n3. Responsabilidades do Fabricante e Importador;\r\n\r\n4. Certificado de Aprovação - CA - Restauração, Lavagem e Higienização;\r\n\r\n5. Responsabilidades do Ministério do Trabalho e Emprego;\r\n\r\n6. Tipos de EPI.', '27.webp', 'treinamento-nr-06-equipamento-de-protecao-individual-epi', 'treinamento', 468, 'NR06'),
(29, 'TREINAMENTO NR 10 BÁSICO FORMAÇÃO - SEGURANÇA EM INSTALAÇÕES E SERVIÇOS EM ELETRICIDADE', 'NR 10 - SEGURANÇA EM INSTALAÇÕES E SERVIÇOS EM ELETRICIDADE - Esta Norma Regulamentadora estabelece os requisitos e condições mínimas objetivando a implementação de medidas de controle e sistemas preventivos, de forma a garantir a segurança e a saúde dos ', 'Público Alvo: Eletricistas, auxiliares, operadores, encarregados, supervisores, técnicos e engenheiros, técnico de segurança do trabalho, mantenedores, projetistas e profissionais de áreas correlatas.\r\n\r\nDescrição: NR 10 - SEGURANÇA EM INSTALAÇÕES E SERVIÇOS EM ELETRICIDADE - Esta Norma Regulamentadora estabelece os requisitos e condições mínimas objetivando a implementação de medidas de controle e sistemas preventivos, de forma a garantir a segurança e a saúde dos trabalhadores que, direta ou indiretamente, interajam em instalações elétricas e serviços com eletricidade.\r\n\r\nCurso Básico de acordo com a NR 10\r\n\r\nFormação - Carga horária: 40 Horas\r\n\r\nConteúdo programático:\r\n\r\n1. Introdução à segurança com eletricidade;\r\n\r\n2. Riscos em instalações e serviços com eletricidade\r\n2.1. o choque elétrico, mecanismos e efeitos;\r\n2.2. arcos elétricos; queimaduras e quedas;\r\n2.3. campos eletromagnéticos.\r\n\r\n3. Técnicas de Análise de Risco.\r\n\r\n4. Medidas de Controle do Risco Elétrico:\r\n4.1 desenergização.\r\n4.2 aterramento funcional (TN / TT / IT); de proteção; temporário;\r\n4.3 equipotencialização;\r\n4.4 seccionamento automático da alimentação;\r\n4.5 dispositivos a corrente de fuga;\r\n4.6 extra baixa tensão;\r\n4.7 barreiras e invólucros;\r\n4.8 bloqueios e impedimentos;\r\n4.9 obstáculos e anteparos;\r\n4.10 isolamento das partes vivas;\r\n4.11 isolação dupla ou reforçada;\r\n4.12 colocação fora de alcance;\r\n4.13 separação elétrica.\r\n\r\n5. Normas Técnicas Brasileiras - NBR da ABNT: NBR-5410, NBR 14039 e outras;\r\n\r\n6. Regulamentações do MTE:\r\n6.1 NRs;\r\n6.2 NR-10 (Segurança em Instalações e Serviços com Eletricidade);\r\n6.3 qualificação; habilitação; capacitação e autorização.\r\n\r\n7. Equipamentos de proteção coletiva;\r\n\r\n8. Equipamentos de proteção individual;\r\n\r\n9. Rotinas de trabalho – Procedimentos:\r\n9.1 instalações desenergizadas;\r\n9.2 liberação para serviços;\r\n9.3 sinalização;\r\n9.4 inspeções de áreas, serviços, ferramental e equipamento.\r\n\r\n10. Documentação de instalações elétricas;\r\n\r\n11. Riscos adicionais:\r\n11.1 altura;\r\n11.2 ambientes confinados;\r\n11.3 áreas classificadas;\r\n11.4 umidade;\r\n11.5 condições atmosféricas;\r\n12. Proteção e combate a incêndios;\r\n12.1 noções básicas;\r\n12.2 medidas preventivas;\r\n12.3 métodos de extinção;\r\n12.4 prática.\r\n\r\n13. Acidentes de origem elétrica:\r\n13.1 causas diretas e indiretas;\r\n13.2 discussão de casos.\r\n\r\n14. Primeiros socorros:\r\n14.1 noções sobre lesões;\r\n14.2 priorização do atendimento;\r\n14.3 aplicação de respiração artificial;\r\n14.4 massagem cardíaca;\r\n14.5 técnicas para remoção e transporte de acidentados;\r\n14.6 práticas.\r\n\r\n15. Responsabilidades.', '28.webp', 'treinamento-nr10-basico-formacao-seguranca-em-instalacoes-e-servicos-em-eletricidade', 'treinamento', 445, 'NR10'),
(59, 'OPERAÇÃO E MANUTENÇÃO DE CABINE PRIMÁRIA', 'Conteúdo programático:  1 INTRODUÇÃO 2 TIPOS DE SUBESTAÇÕES   3 EQUIPAMENTOS 3.1 RAMAL DE ENTRADA', 'Conteúdo programático:\r\n\r\n1. INTRODUÇÃO\r\n\r\n2. TIPOS DE SUBESTAÇÕES\r\n\r\n3. EQUIPAMENTOS\r\n3.1 RAMAL DE ENTRADA\r\n3.2 PARA-RAIOS:\r\n3.3 DISJUNTORES\r\n3.4 CHAVES SECCIONADORES\r\n3.5 TRANSFORMADOR\r\n\r\n4. TRANSFORMADORES PARA INSTRUMENTOS\r\n\r\n5. INSTRUMENTOS DE MEDIÇÃO\r\n\r\n6. PROCEDIMENTO DE SEGURANÇA PARA MANOBRAS\r\n\r\n7. PROCEDIMENTO DE SEGURANÇA EM MANUTENÇÃO ELÉTRICA\r\n7.1 PLANEJAMENTO\r\n7.2 ATERRAMENTO TEMPORÁRIO\r\n\r\n8. PROCEDIMENTO PRÁTICO PARA MANUTENÇÃO DE CABINE\r\n\r\n9. INSTRUMENTOS DE ENSAIOS', '21.webp', 'operacao-e-manutencao-de-cabine-primaria', 'treinamento', 584, ''),
(61, 'ANÁLISE PRELIMINAR DE RISCO - APR', 'Consiste em um estudo antecipado e detalhado de todas as fases do trabalho a fim de detectar os possíveis problemas que poderão acontecer durante a execução.', 'Consiste em um estudo antecipado e detalhado de todas as fases do trabalho a fim de detectar os possíveis problemas que poderão acontecer durante a execução.\r\n\r\nDepois de detectado os possíveis acidentes e problemas, devem ser adotados medidas de controle e neutralização, essas medidas devem envolver toda equipe, criando um clima de trabalho seguro em conjunto.', '', 'analise-preliminar-de-risco-apr', 'servico', 1474, ''),
(62, 'DIAGRAMA UNIFILAR', 'O item 10.2.3 da NR-10 estabelece que todas as empresas estão obrigadas a manter esquemas unifilares atualizados das instalações elétricas dos seus estabelecimentos com as especificações do sistema de aterramento e demais equipamentos e dispositivos de pr', 'O item 10.2.3 da NR-10 estabelece que todas as empresas estão obrigadas a manter esquemas unifilares atualizados das instalações elétricas dos seus estabelecimentos com as especificações do sistema de aterramento e demais equipamentos e dispositivos de proteção.\r\n\r\nDeve-se manter uma cópia atualizada do diagrama na cabine de alta tensão e nos quadros de distribuição de luz e força.', '', 'diagrama-unifilar', 'servico', 579, ''),
(30, 'TREINAMENTO NR 10 BÁSICO RECICLAGEM - SEGURANÇA EM INSTALAÇÕES E SERVIÇOS EM ELETRICIDADE', 'NR 10 - SEGURANÇA EM INSTALAÇÕES E SERVIÇOS EM ELETRICIDADE - Esta Norma Regulamentadora estabelece os requisitos e condições mínimas objetivando a implementação de medidas de controle e sistemas preventivos, de forma a garantir a segurança e a saúde dos ', 'Público Alvo: Eletricistas, auxiliares, operadores, encarregados, supervisores, técnicos e engenheiros, técnico de segurança do trabalho, mantenedores, projetistas e profissionais de áreas correlatas.\r\n\r\nDescrição: NR 10 - SEGURANÇA EM INSTALAÇÕES E SERVIÇOS EM ELETRICIDADE – Esta Norma Regulamentadora estabelece os requisitos e condições mínimas objetivando a implementação de medidas de controle e sistemas preventivos, de forma a garantir a segurança e a saúde dos trabalhadores que, direta ou indiretamente, interajam em instalações elétricas e serviços com eletricidade.\r\n\r\nObservação:\r\n\r\nDeve ser realizado um treinamento de reciclagem bienal e sempre que ocorrer alguma das situações a seguir:\r\n\r\na) Troca de função ou mudança de empresa;\r\nb) Retorno de afastamento ao trabalho ou inatividade, por período superior a três meses;\r\nc) Modificações significativas nas instalações elétricas ou troca de métodos, processos e organização do trabalho.\r\n\r\nA carga horária e o conteúdo programático dos treinamentos de reciclagem destinados ao atendimento acima devem atender as necessidades da situação que o motivou.\r\nOs trabalhos em áreas classificadas devem ser precedidos de treinamento especifico de acordo com risco envolvido.\r\nOs trabalhadores com atividades não relacionadas às instalações elétricas desenvolvidas em zona livre e na vizinhança da zona controlada, conforme define esta NR, devem ser instruídos formalmente com conhecimentos que permitam identificar e avaliar seus possíveis riscos e adotar as precauções cabíveis.\r\n\r\nCarga horária: a partir de 08 Horas\r\n\r\nConteúdo programático:\r\n\r\n1. Deve ser realizado um treinamento de reciclagem bienal e sempre que ocorrer alguma das situações a seguir:\r\n1.1 Troca de função ou mudança de empresa;\r\n1.2 Retorno de afastamento ao trabalho ou inatividade, por período superior a três meses;\r\n1.3 Modificações significativas nas instalações elétricas ou troca de métodos, processos e organização do trabalho.\r\n\r\n2. A carga horária e o conteúdo programático dos treinamentos de reciclagem destinados ao atendimento acima devem atender as necessidades da situação que o motivou.\r\n\r\n3. Os trabalhos em áreas classificadas devem ser precedidos de treinamento especifico de acordo com risco envolvido.\r\n\r\n4. Os trabalhadores com atividades não relacionadas às instalações elétricas desenvolvidas em zona livre e na vizinhança da zona controlada, conforme define esta NR, devem ser instruídos formalmente com conhecimentos que permitam identificar e avaliar seus possíveis riscos e adotar as precauções cabíveis.\r\n\r\nReciclagem - Carga horária: a partir de 08 Horas\r\nConteúdo programático:\r\n\r\n1. Introdução à segurança com eletricidade;\r\n\r\n2. Riscos em instalações e serviços com eletricidade:\r\n2.2 o choque elétrico, mecanismos e efeitos;\r\n2.3 arcos elétricos; queimaduras e quedas;\r\n2.4 campos eletromagnéticos.\r\n\r\n3. Técnicas de Análise de Risco.\r\n\r\n4. Medidas de Controle do Risco Elétrico:\r\n\r\n4.1 desenergização;\r\n4.2 aterramento funcional (TN / TT / IT); de proteção; temporário;\r\n4.3 equipotencialização;\r\n4.4 seccionamento automático da alimentação;\r\n4.5 dispositivos a corrente de fuga;\r\n4.6 extra baixa tensão;\r\n4.7 barreiras e invólucros;\r\n4.8 bloqueios e impedimentos;\r\n4.9 obstáculos e anteparos;\r\n4.10 isolamento das partes vivas;\r\n4.11 isolação dupla ou reforçada;\r\n4.12 colocação fora de alcance;\r\n4.13 separação elétrica.\r\n\r\n5. Normas Técnicas Brasileiras - NBR da ABNT: NBR-5410, NBR 14039 e outras;\r\n\r\n6. Regulamentações do MTE:\r\n6.1 NRs;\r\n6.2 NR 10 (Segurança em Instalações e Serviços com Eletricidade);\r\n6.3 qualificação; habilitação; capacitação e autorização.\r\n\r\n7. Equipamentos de proteção coletiva;\r\n\r\n8. Equipamentos de proteção individual;\r\n\r\n9. Rotinas de trabalho - Procedimentos:\r\n9.1 instalações desenergizadas;\r\n9.2 liberação para serviços;\r\n9.3 sinalização;\r\n9.4 inspeções de áreas, serviços, ferramental e equipamento.\r\n\r\n10. Documentação de instalações elétricas;\r\n\r\n11. Riscos adicionais:\r\n11.1 altura;\r\n11.2 ambientes confinados;\r\n11.3 áreas classificadas;\r\n11.4 umidade;\r\n11.5 condições atmosféricas.\r\n\r\n12. Proteção e combate a incêndios:\r\n12.1 noções básicas;\r\n12.2 medidas preventivas;\r\n12.3 métodos de extinção;\r\n12.4 prática.\r\n\r\n13. Acidentes de origem elétrica:\r\n13.1 causas diretas e indiretas;\r\n13.2 discussão de casos.\r\n\r\n14. Primeiros socorros:\r\n14.1 noções sobre lesões;\r\n14.2 priorização do atendimento;\r\n14.3 aplicação de respiração artificial;\r\n14.4 massagem cardíaca;\r\n14.5 técnicas para remoção e transporte de acidentados;\r\n14.6 práticas.\r\n\r\n15. Responsabilidades.', '06.webp', 'treinamento-nr10-basico-reciclagem-seguranca-em-instalacoes-e-servicos-em-eletricidade', 'treinamento', 2466, 'NR10'),
(64, 'PERMISSÃO DE TRABALHO - PT', 'É um documento utilizado em trabalhos de risco elevado, tais como  Trabalho em Altura; Espaço Confinado; Abertura de Linha; Trabalho a Quente; Travamento de Fonte de Energia.', 'É um documento utilizado em trabalhos de risco elevado, tais como\r\n\r\nTrabalho em Altura;\r\nEspaço Confinado;\r\nAbertura de Linha;\r\nTrabalho a Quente;\r\nTravamento de Fonte de Energia.\r\nÉ um formulário usado para controlar o acesso ao trabalho em áreas de risco elevado por período pré-determinado pela empresa.\r\n\r\nPortanto é uma ferramenta de avaliação, documentação e permissão de exposição à possíveis riscos causadores de acidentes de trabalho e doenças ocupacionais.\r\n\r\nUma das fases da PT Permissão de Trabalho é a APR - Análise Preliminar de Risco.', '', 'permissao-de-trabalho-pt', 'servico', 1543, ''),
(71, 'LAUDO DE MOTO GERADOR OU ATESTADO DE ABRANGÊNCIA DO GRUPO MOTOGERADOR PARA FINS DE AVCB', 'É exigido pelo CBPMESP-Corpo de Bombeiros da Policia Militar do Estado de São Paulo, tem como objetivo atestar a conformidade do grupo gerador quanto ao atendimento às condições de instalações conforme ABNT-NBR-10.898', 'É exigido pelo CBPMESP-Corpo de Bombeiros da Policia Militar do Estado de São Paulo, tem como objetivo atestar a conformidade do grupo gerador quanto ao atendimento às condições de instalações conforme ABNT-NBR-10.898 de Setembro de 1999, além do atendimento à condições operativas, sistemas atendidos, do sistema de alimentação de emergência.', '', 'laudo-de-moto-gerador-ou-atestado-de-abrangencia-do-grupo-motogerador-para-fins-de-avcb', 'laudo', 1680, ''),
(74, 'LAUDO DE PARA-RAIOS OU SPDA PARA FINS DE AVCB', 'O Laudo de Para-Raios é obrigatório e a emissão desse Laudo deve estar de acordo com a NBR-5410, NBR-5419 e NBR-15749.', 'O Laudo de Para-Raios é obrigatório e a emissão desse Laudo deve estar de acordo com a NBR-5410, NBR-5419 e NBR-15749.\r\n\r\nNo laudo deve constar se a instalação obedece ao nível de proteção adequado, verificar o sistema de captação e também o sistema de descidas observando sempre as possíveis não conformidades, avaliar o sistema de aterramento e efetuar medições na malha de aterramento.', '', 'laudo-de-pararaios-ou-spda-para-fins-de-avcb', 'laudo', 962, ''),
(76, 'Manutenção em Caldeiras - NR13', 'A Gambeti realiza manutenção completa em Caldeiras', 'A Gambeti realiza manutenção completa em Caldeiras:\r\n\r\n1. Manutenção do queimador\r\n2. Regulagem do queimador\r\n3. Substituição de pedra cônica\r\n4. Substituição de bucha traseira\r\n5. Substituição / reforma do trapézio\r\n6 .Substituição da tubulação\r\n7. Substituição de espelhos\r\n8. Serviços de soldagem\r\n9. Reforma em geral\r\n\r\nEntre outros', '', 'nr13-manutencao-em-caldeiras', 'inspecao', 2591, ''),
(31, 'TREINAMENTO NR 10 CURSO COMPLEMENTAR - RECICLAGEM PARA SEGURANÇA NO SISTEMA ELÉTRICO DE POTÊNCIA (SEP) E EM SUAS PROXIMIDADES', 'NR 10 - SEP (SISTEMA ELÉTRICO DE POTÊNCIA) - Esta Norma Regulamentadora estabelece os requisitos e condições mínimas objetivando a implementação de medidas de controle e sistemas preventivos, de forma a garantir a segurança e a saúde dos trabalhadores que', 'Público Alvo: Eletricistas, auxiliares, operadores, encarregados, supervisores, técnicos e engenheiros, técnico de segurança do trabalho, mantenedores, projetistas e profissionais de áreas correlatas.\r\n\r\nDescrição: NR 10 - SEP (SISTEMA ELÉTRICO DE POTÊNCIA) - Esta Norma Regulamentadora estabelece os requisitos e condições mínimas objetivando a implementação de medidas de controle e sistemas preventivos, de forma a garantir a segurança e a saúde dos trabalhadores que, direta ou indiretamente, interajam em instalações elétricas e serviços com eletricidade.\r\n\r\nObservação:\r\n\r\n1. Deve ser realizado um treinamento de reciclagem bienal e sempre que ocorrer alguma das situações a seguir:\r\n\r\na) Troca de função ou mudança de empresa;\r\n\r\nb) Retorno de afastamento ao trabalho ou inatividade, por período superior a três meses;\r\n\r\nc) Modificações significativas nas instalações elétricas ou troca de métodos, processos e organização do trabalho.\r\n\r\n2. A carga horária e o conteúdo programático dos treinamentos de reciclagem destinados ao atendimento acima devem atender as necessidades da situação que o motivou.\r\n\r\n3. Os trabalhos em áreas classificadas devem ser precedidos de treinamento especifico de acordo com risco envolvido.\r\n\r\n4. Os trabalhadores com atividades não relacionadas às instalações elétricas desenvolvidas em zona livre e na vizinhança da zona controlada, conforme define esta NR, devem ser instruídos formalmente com conhecimentos que permitam identificar e avaliar seus possíveis riscos e adotar as precauções cabíveis.\r\n\r\nCarga horária: a partir de 08 Horas\r\n\r\n(*) Estes tópicos deverão ser desenvolvidos e dirigidos especificamente para as condições de trabalho características de cada ramo, padrão de operação, de nível de tensão e de outras peculiaridades específicas ao tipo ou condição especial de atividade, sendo obedecida a hierarquia no aperfeiçoamento técnico do trabalhador.\r\n\r\nConteúdo programático:\r\n\r\n1. Organização do Sistema Elétrico de Potencia – SEP;\r\n\r\n2. Organização do trabalho:\r\n2.1 programação e planejamento dos serviços;\r\n2.2 trabalho em equipe;\r\n2.3 prontuário e cadastro das instalações;\r\n2.4 métodos de trabalho;\r\n2.5 comunicação.\r\n\r\n3. Aspectos comportamentais;\r\n\r\n4. Condições impeditivas para serviços;\r\n\r\n5. Riscos típicos no SEP e sua prevenção: (*)\r\n5.1 proximidade e contatos com partes energizadas;\r\n5.2 indução;\r\n5.3 descargas atmosféricas;\r\n5.4 estática;\r\n5.5 campos elétricos e magnéticos;\r\n5.6 comunicação e identificação;\r\n5.7 trabalhos em altura, máquinas e equipamentos especiais.\r\n\r\n6. Técnicas de análise de Risco no S E P; (*)\r\n\r\n7. Procedimentos de trabalho - análise e discussão; (*)\r\n\r\n8. Técnicas de trabalho sob tensão: (*)\r\n8.1 em linha viva;\r\n8.2 ao potencial;\r\n8.3 em áreas internas;\r\n8.4 trabalho a distância;\r\n8.5 trabalhos noturnos;\r\n8.6 ambientes subterrâneos.\r\n\r\n9. Equipamentos e ferramentas de trabalho (escolha, uso, conservação, verificação, ensaios); (*)\r\n\r\n10. Sistemas de proteção coletiva; (*)\r\n\r\n11. Equipamentos de proteção individual; (*)\r\n\r\n12. Posturas e vestuários de trabalho; (*)\r\n\r\n13. Segurança com veículos e transporte de pessoas, materiais e equipamentos; (*)\r\n\r\n14. Sinalização e isolamento de áreas de trabalho; (*)\r\n\r\n15. Liberação de instalação para serviço e para operação e uso; (*)\r\n\r\n16. Treinamento em técnicas de remoção, atendimento, transporte de acidentados; (*)\r\n\r\n17. Acidentes típicos (*) - Análise, discussão, medidas de proteção;\r\n\r\n18. Responsabilidades; (*)\r\n\r\n', '41.webp', 'treinamento-nr10-curso-complementar-reciclagem-para-seguranca-no-sistema-eletrico--de-potencia-sep-e-em-suas-proximidades', 'treinamento', 338, 'NR10'),
(32, 'TREINAMENTO NR 10 CURSO COMPLEMENTAR - FORMAÇÃO PARA SEGURANÇA NO SISTEMA ELÉTRICO DE POTÊNCIA (SEP) E EM SUAS PROXIMIDADES', 'NR 10 - SEP (SISTEMA ELÉTRICO DE POTÊNCIA) - Esta Norma Regulamentadora estabelece os requisitos e condições mínimas objetivando a implementação de medidas de controle e sistemas preventivos, de forma a garantir a segurança e a saúde dos trabalhadores que', 'Público Alvo: Eletricistas, auxiliares, operadores, encarregados, supervisores, técnicos e engenheiros, técnico de segurança do trabalho, mantenedores, projetistas e profissionais de áreas correlatas.\r\n\r\nDescrição: NR 10 - SEP (SISTEMA ELÉTRICO DE POTÊNCIA) – Esta Norma Regulamentadora estabelece os requisitos e condições mínimas objetivando a implementação de medidas de controle e sistemas preventivos, de forma a garantir a segurança e a saúde dos trabalhadores que, direta ou indiretamente, interajam em instalações elétricas e serviços com eletricidade.\r\n\r\nObservação:\r\n\r\nÉ pré-requisito para frequentar este curso complementar, ter participado com aproveitamento satisfatório do curso NR 10 Básico.\r\n\r\nCarga horária: 40 Horas\r\n\r\n(*) Estes tópicos deverão ser desenvolvidos e dirigidos especificamente para as condições de trabalho características de cada ramo, padrão de operação, de nível de tensão e de outras peculiaridades específicas ao tipo ou condição especial de atividade, sendo obedecida a hierarquia no aperfeiçoamento técnico do trabalhador.\r\n\r\nConteúdo programático:\r\n\r\n1. Organização do Sistema Elétrico de Potencia – SEP;\r\n\r\n2. Organização do trabalho:\r\n2.1 programação e planejamento dos serviços;\r\n2.2 trabalho em equipe;\r\n2.3 prontuário e cadastro das instalações;\r\n2.4 métodos de trabalho;\r\n2.5 comunicação.\r\n\r\n3. Aspectos comportamentais;\r\n\r\n4. Condições impeditivas para serviços;\r\n\r\n5. Riscos típicos no SEP e sua prevenção: (*)\r\n5.1 proximidade e contatos com partes energizadas;\r\n5.2 indução;\r\n5.3 descargas atmosféricas;\r\n5.4 estática;\r\n5.5 campos elétricos e magnéticos;\r\n5.6 comunicação e identificação;\r\n5.7 trabalhos em altura, máquinas e equipamentos especiais.\r\n\r\n6. Técnicas de análise de Risco no SEP; (*)\r\n\r\n7. Procedimentos de trabalho - análise e discussão; (*)\r\n\r\n8. Técnicas de trabalho sob tensão: (*)\r\n8.1 em linha viva;\r\n8.2 ao potencial;\r\n8.3 em áreas internas;\r\n8.4 trabalho a distância;\r\n8.5 trabalhos noturnos;\r\n8.6 ambientes subterrâneos.\r\n\r\n9. Equipamentos e ferramentas de trabalho (escolha, uso, conservação, verificação, ensaios); (*)\r\n\r\n10. Sistemas de proteção coletiva; (*)\r\n\r\n11. Equipamentos de proteção individual; (*)\r\n\r\n12. Posturas e vestuários de trabalho; (*)\r\n\r\n13. Segurança com veículos e transporte de pessoas, materiais e equipamentos; (*)\r\n\r\n14. Sinalização e isolamento de áreas de trabalho; (*)\r\n\r\n15. Liberação de instalação para serviço e para operação e uso; (*)\r\n\r\n16. Treinamento em técnicas de remoção, atendimento, transporte de acidentados; (*)\r\n\r\n17. Acidentes típicos (*) - Análise, discussão, medidas de proteção;\r\n\r\n18. Responsabilidades; (*)', '33.webp', 'treinamento-nr10-curso-complementar-formacao-para-seguranca-no-sistema-eletrico-de-potencia-sep-e-em-suas-proximidades', 'treinamento', 399, 'NR10'),
(77, 'Inspeção em Vasos de Pressão - NR 13', 'A Gambeti oferece inspeções e manutenções em atendimento a NR-13 VASOS DE PRESSÃO.', 'A Gambeti oferece inspeções e manutenções em atendimento a NR-13 VASOS DE PRESSÃO.\r\n\r\nInspeções: Iniciais / Periódica / Extraordinária\r\n\r\nServiços:\r\n\r\n1. Exame Externo\r\n2. Exame Interno\r\n3. Teste Hidrostático caso necessário\r\n4. Confecção da Placa de Identificação\r\n5. Análise do Prontuário do Vaso de Pressão\r\n6. Reconstituição do Prontuário do equipamento\r\n7. Medição de Espessura por Ultrassom\r\n8. Partícula Magnética\r\n9. Líquido Penetrante\r\n10. Anotação no Livro de Registro de Segurança\r\n11. Abertura do Livro de Registro de Segurança\r\n12. Elaboração do Projeto de Instalação\r\n13. Cálculo da PMTA\r\n14. Emissão de ART', '', 'nr13-vasos-de-pressao', 'inspecao', 1525, ''),
(33, 'TREINAMENTO NR 11 - CAMINHÃO CAÇAMBA BASCULANTE / MUNCK', 'NR 11 - TRANSPORTE, MOVIMENTAÇÃO, ARMAZENAGEM E MANUSEIO DE MATERIAIS - Normas de segurança para operação de elevadores, guindastes, transportadores industriais e máquinas transportadoras. Estabelece os requisitos de segurança a serem observados nos locai', 'TREINAMENTO NR 11 - CAMINHÃO CAÇAMBA BASCULANTE / MUNCK\r\n\r\nPúblico Alvo: Diretores, gerentes, engenheiros, coordenadores, supervisores, operadores de Empilhadeira, Guindauto, Retroescavadeira, Ponte Rolante, Mopp, Bobcat, Munck, Paleteira e demais interessados em conhecer as normas e técnicas da NR 11.\r\n\r\nDescrição: NR 11 - TRANSPORTE, MOVIMENTAÇÃO, ARMAZENAGEM E MANUSEIO DE MATERIAIS - Normas de segurança para operação de elevadores, guindastes, transportadores industriais e máquinas transportadoras. Estabelece os requisitos de segurança a serem observados nos locais de trabalho, no que se refere ao transporte, à movimentação, à armazenagem e ao manuseio de materiais, tanto de forma mecânica quanto manual, objetivando a prevenção de infortúnios laborais.\r\n\r\nCarga horária:\r\n\r\nFormação - Carga horária: a partir de 08 Horas\r\nReciclagem - Carga horária: a partir de 08 Horas\r\n\r\nEquipamento: Caminhão Caçamba Basculante / Caminhão Munck\r\n\r\nConteúdo programático:\r\n\r\n1. Introdução a Engenharia de Segurança do Trabalho;\r\n\r\n2. Acidentes do Trabalho - causas e consequências;\r\n\r\n3. Legislação;\r\n\r\n4. Responsabilidades do empregado na utilização do equipamento;\r\n\r\n5. Componentes do Equipamento;\r\n\r\n6. Tipos do equipamento transportador;\r\n\r\n7. Equipamentos de Proteção Individual e Coletiva(EPI / EPC);\r\n\r\n8. Elaboração do check-list para inspeção diária do equipamento;\r\n\r\n9. Como fazer a Inspeção diária do equipamento;\r\n\r\n10. Inspeção de pré-uso e\r\n\r\n11. Prático de Operação', '08.webp', 'treinamento-nr11-caminhao-cacamba-basculante-munck', 'treinamento', 1625, 'NR11'),
